export function TruthBars({ type, size, bars }) {
  var sz = size || 14;
  var col = type === "truth" ? C.green : type === "lie" ? C.red : C.grey;
  var w = sz * 0.6, h = sz * 0.22;
  var isU = type === "unsure";
  var fc = isU ? 0 : (bars != null ? bars : 4);
  return <div style={{ display:"flex", gap: sz*0.2, alignItems:"center" }}>{[0,1,2,3].map(function(i){return <div key={i} style={{ width:w, height:h, borderRadius: h/2, background: isU ? C.grey : (i < fc ? col : "#d1d5db") }} />;})}</div>;
}

function Logo({ size }: { color?: string; size?: number }) {
  var s = size || 22;
  var fs = Math.round(s * 0.8);
  var sw = (fs * 0.8 / 56).toFixed(2);
  var r = Math.round(s * 0.15);
  return <svg width={s} height={s} viewBox={"0 0 "+s+" "+s} xmlns="http://www.w3.org/2000/svg"><rect width={s} height={s} rx={r} fill="#1C1917"/><text x="50%" y="56%" dominantBaseline="central" textAnchor="middle" fontFamily="'Instrument Serif', Georgia, serif" fontSize={fs} fill="#D4A574" stroke="#D4A574" strokeWidth={sw} paintOrder="stroke fill">V</text></svg>;
}

export function VerloWordmark({ fontSize = 20, light = false }: { fontSize?: number; light?: boolean }) {
  var tc = light ? "#fff" : "#D4A574";
  var sw = (fontSize * 0.8 / 56).toFixed(2) + "px";
  return <span style={{fontFamily:"'Instrument Serif', Georgia, serif",fontSize,color:tc,letterSpacing:"0.03em",WebkitTextStroke:sw+" "+tc,lineHeight:1}}>Verlo</span>;
}

function VerloLockup({ height = 24 }: { height?: number }) {
  var w = height * (310/60);
  return <svg width={w} height={height} viewBox="0 0 310 60" xmlns="http://www.w3.org/2000/svg"><rect width="52" height="52" rx="8" y="4" fill="#1C1917"/><text x="26" y="36" dominantBaseline="central" textAnchor="middle" fontFamily="'Instrument Serif', Georgia, serif" fontSize="41.6" fill="#D4A574" stroke="#D4A574" strokeWidth="0.8" paintOrder="stroke fill">V</text><text x="66" y="48" fontFamily="'Instrument Serif', Georgia, serif" fontSize="50" fill="#D4A574" stroke="#D4A574" strokeWidth="0.8" paintOrder="stroke fill" letterSpacing="0.03em">Verlo</text></svg>;
}

