function HelpFAQ(){var [oi,setOi]=useState(null);var faqs=[{q:"How accurate is TruthOrLie?",a:"Our technology provides confidence scores with every prediction."},{q:"How does TruthOrLie work?",a:"We employ advanced AI algorithms to analyze thousands of data points."},{q:"How is it different from a polygraph?",a:"TruthOrLie relies on behavioral analysis. It is non-invasive."},{q:"What file formats are supported?",a:"Video: .mp4, .mov. Audio: .mp3, .wav, .m4a, .aac, .flac, .ogg, .opus, .webm."},{q:"Is my data secure?",a:"All uploads are encrypted in transit and at rest."}];return <HelpShell activeTab="FAQ"><h2 style={{fontSize:18,fontWeight:700,color:C.text,marginBottom:24}}>Frequently Asked Questions</h2>{faqs.map(function(f,i){return <div key={i} style={{background:C.bgSub,borderRadius:8,marginBottom:2}}><div onClick={function(){setOi(oi===i?null:i);}} style={{padding:"16px 20px",display:"flex",justifyContent:"space-between",alignItems:"center",cursor:"pointer"}}><span style={{fontSize:14,fontWeight:600,color:C.text}}>{f.q}</span><span style={{fontSize:18,color:C.textMuted,transform:oi===i?"rotate(45deg)":"none",transition:"transform 0.2s",flexShrink:0,marginLeft:16}}>+</span></div>{oi===i&&<div style={{padding:"0 20px 16px"}}><p style={{fontSize:13,color:C.textSec,lineHeight:1.6,margin:0}}>{f.a}</p></div>}</div>;})}</HelpShell>;}

function ErrorModal({title,message,detail,primaryBtn,secondaryBtn}){
  return <div style={{minHeight:"100%",background:"rgba(0,0,0,0.5)",display:"flex",alignItems:"center",justifyContent:"center",padding:40}}>
    <div style={{background:C.bg,borderRadius:20,width:420,position:"relative",padding:"36px 32px 28px",textAlign:"center"}}>
      <div style={{position:"absolute",top:16,right:16,width:32,height:32,borderRadius:8,background:C.bgSub,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}><span style={{color:C.textMuted}}>x</span></div>
      <div style={{width:56,height:56,borderRadius:16,background:"#fef2f2",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 20px"}}><svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke={C.red} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg></div>
      <h2 style={{fontSize:20,fontWeight:700,color:C.text,margin:"0 0 8px"}}>{title||"Something went wrong"}</h2>
      <p style={{fontSize:14,color:C.textSec,lineHeight:1.6,margin:"0 0 24px",maxWidth:320,marginLeft:"auto",marginRight:"auto"}}>{message||"An unexpected error occurred. Please try again."}</p>
      {detail&&<div style={{background:"#fef2f2",borderRadius:10,padding:"14px 20px",marginBottom:24,border:"1px solid #fecaca",textAlign:"left"}}><div style={{display:"flex",alignItems:"flex-start",gap:8}}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={C.red} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" style={{flexShrink:0,marginTop:2}}><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg><p style={{fontSize:12,color:"#991b1b",margin:0,lineHeight:1.5,fontFamily:"monospace"}}>{detail}</p></div></div>}
      <div style={{display:"flex",flexDirection:"column",gap:8}}><button style={{width:"100%",padding:"13px 0",borderRadius:10,border:"none",background:C.brand,color:"#fff",fontSize:14,fontWeight:600}}>{primaryBtn||"Try Again"}</button>{secondaryBtn&&<button style={{width:"100%",padding:"13px 0",borderRadius:10,border:"1.5px solid "+C.border,background:C.bg,color:C.textSec,fontSize:14,fontWeight:600}}>{secondaryBtn}</button>}</div>
    </div>
  </div>;
}

